import{_ as o,o as e,c as t,a2 as r}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"G07: 研發成果實質性 - 經營審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/6442_光聖/20260504/G07_研發成果實質性.md","filePath":"審計報告庫/經營審計/6442_光聖/20260504/G07_研發成果實質性.md"}'),l={name:"審計報告庫/經營審計/6442_光聖/20260504/G07_研發成果實質性.md"};function n(i,a,s,h,d,_){return e(),t("div",null,[...a[0]||(a[0]=[r('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的經營洞見。</p><h1 id="g07-研發成果實質性-經營審計專家報告" tabindex="-1">G07: 研發成果實質性 - 經營審計專家報告 <a class="header-anchor" href="#g07-研發成果實質性-經營審計專家報告" aria-label="Permalink to &quot;G07: 研發成果實質性 - 經營審計專家報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>最近三年研發成果預期項目是否有如期完成？最近三年重大研發成果為何？具備何種變現潛力？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>研發為應用導向改良——高芯數光纜量產化（6,912→13,824芯）、RF轉型、CPO布局（ELS驗證中）。投入0.89%營收但變現效率高，貢獻90%營收成長。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>A (良)</strong>：效率卓越但強度不足。R&amp;D NT$9,362萬（營收0.89%），專利&gt;180項。6,912芯量產規格業界最高，CPO-ELS進最終驗證，RF GPM個位數攀升至20-30%。0.89%強度低於同業但產出豐碩，屬精準聚焦型。風險在若技術路線大轉彎能力不足。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p>三大研發成果：(1)高芯數光纜288→6,912芯量產，13,824芯開發中，為Google TPU Ironwood關鍵零組件。(2)RF從有線電視完全退出轉向低軌衛星/航太/車用，GPM從個位數升至20-30%。(3)CPO-ELS進入大廠最終驗證，2026年有望量產。形成短中長期組合——高芯數當下變現、RF中期變現、CPO長期變現。</p><blockquote><p>180項專利多為應用改良型非基礎架構型，可被設計繞過。真正護城河在Google認證+量產良率——競爭對手有專利也無法快速複製的Know-how。與客戶共享專利雖降低IP獨佔性但強化客戶黏性。</p></blockquote><p>研發投入NT$9,362萬對應光通訊營收年增~NT$42億（研發產出比~45倍）。但營收成長主要來自Google AI CAPEX爆發非純研發驅動，且RF轉型尚未顯著貢獻營收增量。0.89%研發強度若未來技術路線偏離Google需求則應變不足。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><strong>研發深度不足警訊</strong>：0.89%強度在矽光子/CPO轉型關鍵期可能不足。華星光/聯亞等積極投入者若突破CPO技術，光聖可能被彎道超車。</li><li><strong>專利護城河強度有限挑戰</strong>：&gt;180項專利多應用改良型非基礎型，競爭對手可設計繞過。</li><li><strong>自研能力能否支撐下一代競爭</strong>：歷次技術跳躍靠收購非自研，若缺收購標的則應變能力存疑。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><strong>研發產出比極高</strong>：NT$9,362萬對應光通訊年增營收約NT$42億，ROI 45倍。</li><li><strong>短中長期成果組合健康</strong>：高芯數（當下）→RF轉型（中期）→CPO ELS（長期）接力明確。</li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><strong>web_search</strong>：光聖 6442 研發成果/專利/CPO/FAU/矽光子布局</li><li><strong>web_fetch</strong>：富果法說會備忘錄(2026/3/12)確認研發進度與量產時程</li><li><strong>PDF分析</strong>：2025年合併財報R&amp;D費用NT$9,362萬</li><li><strong>原始數據</strong>：stock_id=6442, R&amp;D data from financial reports and investor conferences</li></ul>',19)])])}const p=o(l,[["render",n]]);export{g as __pageData,p as default};
